// Preparar payload para la consulta
var now = new Date();
var y = now.getFullYear();
var m = String(now.getMonth() + 1).padStart(2, '0');
var lastDay = new Date(y, now.getMonth() + 1, 0).getDate();

msg.startDate = y + m + '01';
msg.endDate = y + m + String(lastDay).padStart(2, '0');
msg.sync_uuid = (
  Date.now().toString(36).toUpperCase().slice(-4) +
  Math.random().toString(36).substring(2, 10).toUpperCase()
);

node.warn('[Sync-SS] Iniciando sync ' + msg.sync_uuid + ' periodo ' + msg.startDate + '-' + msg.endDate);
return msg;

var rows = msg.payload;
var sync_uuid = msg.sync_uuid || 'N/A';
var startDate = msg.startDate || '';
var endDate = msg.endDate || '';
var timestamp = new Date().toISOString();

if (!rows || !Array.isArray(rows) || rows.length === 0) {
  node.warn('[Sync-SS] Sin datos para sync');
  return null;
}

// Generar cabecera + filas para Google Sheets
// Formato: CODIGO | CUENTA | RUBRO | DEBE | HABER | SALDO | PERIODO | FECHA_SYNC
var cabecera = ['CODIGO', 'CUENTA', 'RUBRO', 'DEBE_PERIODO', 'HABER_PERIODO', 'SALDO_PERIODO', 'PERIODO', 'FECHA_SYNC', 'SYNC_UUID'];

var filas = [];
for (var i = 0; i < rows.length; i++) {
  var r = rows[i];
  filas.push([
    r.CODIGO || '',
    r.CUENTA || '',
    r.NRubro || '',
    parseFloat(r.DEBE_PERIODO) || 0,
    parseFloat(r.HABER_PERIODO) || 0,
    (parseFloat(r.DEBE_PERIODO) || 0) - (parseFloat(r.HABER_PERIODO) || 0),
    startDate + '-' + endDate,
    timestamp,
    sync_uuid
  ]);
}

msg.payload = {
  cabecera: cabecera,
  filas: filas,
  total: filas.length,
  sync_uuid: sync_uuid,
  periodo: startDate + '-' + endDate,
  timestamp: timestamp,
  source: 'node-red'
};

msg.headers = { 'Content-Type': 'application/json' };

node.warn('[Sync-SS] ' + filas.length + ' filas listas para sync UUID=' + sync_uuid);
return msg;

var statusCode = msg.statusCode || 0;
if (statusCode >= 200 && statusCode < 300) {
  node.warn('[Sync-SS] Sync exitoso a Google Sheets. Status: ' + statusCode);
} else {
  node.error('[Sync-SS] Error en sync. Status: ' + statusCode + ' - ' + JSON.stringify(msg.payload));
}
return msg;
